INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Royal Gallery', 2, '/placeholder.svg', 'Welcome to the Royal Gallery where magnificent paintings of Disney princesses adorn the walls.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Crystal Chamber', 3, '/placeholder.svg', 'This sparkling Crystal Chamber features stunning chandeliers and magical decorations.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Princess Suite', 4, '/placeholder.svg', 'Step into the Princess Suite, where dreams come true with beautiful furnishings fit for royalty.'),
('412e3a5a-2a6d-42d6-8ba1-5308b3c531a1', 'Castle Terrace', 5, '/placeholder.svg', 'From this terrace, enjoy breathtaking views of the Magic Kingdom park below.');
INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('576c1dcc-1894-41a8-9686-ddb4546738aa', 'Sleeping Beauty Gallery', 2, '/placeholder.svg', 'Walk through the enchanted tale of Sleeping Beauty told through beautiful dioramas.'),
('576c1dcc-1894-41a8-9686-ddb4546738aa', 'Dragon Lair', 3, '/placeholder.svg', 'Descend into the mysterious Dragon Lair where Maleficent awaits in dragon form.'),
('576c1dcc-1894-41a8-9686-ddb4546738aa', 'Tower Room', 4, '/placeholder.svg', 'Aurora once slept in this tower room, surrounded by magic and mystery.'),
('576c1dcc-1894-41a8-9686-ddb4546738aa', 'Castle Courtyard', 5, '/placeholder.svg', 'The beautiful courtyard offers a peaceful spot with stunning castle architecture.');
INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('f67e89fa-2a35-4ed2-a598-d8378d3899e6', 'Stained Glass Gallery', 2, '/placeholder.svg', 'Marvel at the beautiful stained glass windows depicting classic Disney tales.'),
('f67e89fa-2a35-4ed2-a598-d8378d3899e6', 'Dragon Cave', 3, '/placeholder.svg', 'Venture into the legendary Dragon Cave beneath the castle.'),
('f67e89fa-2a35-4ed2-a598-d8378d3899e6', 'Royal Chapel', 4, '/placeholder.svg', 'A serene chapel with gothic architecture and magical ambiance.'),
('f67e89fa-2a35-4ed2-a598-d8378d3899e6', 'Tapestry Hall', 5, '/placeholder.svg', 'Admire the exquisite tapestries telling stories of knights and princesses.');
INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('5c3e12f7-5869-4ef4-9918-084dd5f77e1f', 'Garden of Wonder', 2, '/placeholder.svg', 'A magical garden celebrating 13 Disney princess and queen stories.'),
('5c3e12f7-5869-4ef4-9918-084dd5f77e1f', 'Tower of Courage', 3, '/placeholder.svg', 'Climb the Tower of Courage to discover tales of bravery and adventure.'),
('5c3e12f7-5869-4ef4-9918-084dd5f77e1f', 'Hall of Dreams', 4, '/placeholder.svg', 'Walk through the Hall where every princess dream is celebrated.'),
('5c3e12f7-5869-4ef4-9918-084dd5f77e1f', 'Starlight Pavilion', 5, '/placeholder.svg', 'End your tour under a magical starlit sky in this enchanting pavilion.');
INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('ffa6c189-6726-4245-b3b9-0cb8496ec688', 'Once Upon a Time Gallery', 2, '/placeholder.svg', 'Experience the stories of Snow White and other beloved Disney characters.'),
('ffa6c189-6726-4245-b3b9-0cb8496ec688', 'Royal Chamber', 3, '/placeholder.svg', 'A grand royal chamber with stunning Chinese-inspired architectural details.'),
('ffa6c189-6726-4245-b3b9-0cb8496ec688', 'Crystal Grotto', 4, '/placeholder.svg', 'Journey through the Crystal Grotto with magical light displays.'),
('ffa6c189-6726-4245-b3b9-0cb8496ec688', 'Sky Bridge', 5, '/placeholder.svg', 'Walk across the highest bridge in any Disney castle with panoramic views.');
INSERT INTO disney_castle_rooms (castle_id, room_name, order_index, panorama_url, audio_guide_text) VALUES
('d60bcb41-1044-4d6b-8931-993aa4c08d42', 'Sakura Room', 2, '/placeholder.svg', 'A beautiful room decorated with cherry blossom motifs celebrating Japanese culture.'),
('d60bcb41-1044-4d6b-8931-993aa4c08d42', 'Golden Hall', 3, '/placeholder.svg', 'The Golden Hall shimmers with elegant decorations and royal treasures.'),
('d60bcb41-1044-4d6b-8931-993aa4c08d42', 'Tea Garden', 4, '/placeholder.svg', 'A tranquil Japanese tea garden within the castle grounds.'),
('d60bcb41-1044-4d6b-8931-993aa4c08d42', 'Imperial Lookout', 5, '/placeholder.svg', 'From this lookout, see the entire Tokyo DisneySea and Disneyland Resort.');